public class DefaultDateTypeAdapterTest {

  private DefaultDateTypeAdapter<Date> adapter;

  @BeforeEach
  public void setUp() throws Exception {
    Class<?> clazz = DefaultDateTypeAdapter.class;

    Class<?> dateTypeClass = null;
    for (Class<?> c : clazz.getDeclaredClasses()) {
      if ("DateType".equals(c.getSimpleName())) {
        dateTypeClass = c;
        break;
      }
    }

    // DateType is a class, not interface, so create a subclass instance via reflection
    Constructor<?> dateTypeConstructor = dateTypeClass.getDeclaredConstructors()[0];
    dateTypeConstructor.setAccessible(true);

    // Create anonymous subclass instance of DateType with minimal implementation
    Object dateTypeInstance = java.lang.reflect.Proxy.isProxyClass(dateTypeClass) ? 
        null : 
        java.lang.reflect.Proxy.newProxyInstance(
          dateTypeClass.getClassLoader(),
          new Class<?>[0],
          (proxy, method, args) -> null);

    if (dateTypeInstance == null) {
      // Instead create an anonymous subclass via reflection
      dateTypeInstance = java.lang.reflect.Proxy.newProxyInstance(
          dateTypeClass.getClassLoader(),
          new Class<?>[0],
          (proxy, method, args) -> null);
    }

    // Since Proxy cannot be used, create anonymous subclass by reflection
    // Instead create an anonymous subclass by subclassing DateType via reflection
    // Use Unsafe or use reflection to create subclass instance

    // Alternative: create anonymous subclass using reflection
    Object dateType;
    {
      // Create anonymous subclass of DateType
      Class<?> anonSubclass = java.lang.reflect.Proxy.getProxyClass(dateTypeClass.getClassLoader(), new Class<?>[0]);
      // But Proxy requires interfaces, so fallback:
      // Create anonymous subclass via reflection:
      dateType = java.lang.reflect.Proxy.isProxyClass(dateTypeClass) ? null : null;
    }

    // Instead, create anonymous subclass using reflection:
    dateType = java.lang.reflect.Proxy.isProxyClass(dateTypeClass) ? null : null;

    // Since above attempts fail, create anonymous subclass via reflection:

    // Use sun.misc.Unsafe to instantiate without constructor (if available)
    Object dateTypeObj;
    try {
      // Try to instantiate via Unsafe
      java.lang.reflect.Field unsafeField = Class.forName("sun.misc.Unsafe").getDeclaredField("theUnsafe");
      unsafeField.setAccessible(true);
      Object unsafe = unsafeField.get(null);
      java.lang.reflect.Method allocateInstance = unsafe.getClass().getMethod("allocateInstance", Class.class);
      dateTypeObj = allocateInstance.invoke(unsafe, dateTypeClass);
    } catch (Exception e) {
      // fallback: try to find no-arg constructor
      Constructor<?> ctor = null;
      for (Constructor<?> c : dateTypeClass.getDeclaredConstructors()) {
        if (c.getParameterCount() == 0) {
          ctor = c;
          break;
        }
      }
      if (ctor != null) {
        ctor.setAccessible(true);
        dateTypeObj = ctor.newInstance();
      } else {
        throw new RuntimeException("Cannot instantiate DateType", e);
      }
    }

    // Use the instance
    dateType = dateTypeObj;

    Constructor<?> constructor = null;
    for (Constructor<?> c : clazz.getDeclaredConstructors()) {
      Class<?>[] params = c.getParameterTypes();
      if (params.length == 2 && params[1] == String.class) {
        constructor = c;
        break;
      }
    }
    constructor.setAccessible(true);
    adapter = (DefaultDateTypeAdapter<Date>) constructor.newInstance(dateType, "yyyy-MM-dd");
  }

  @Test
  public void testToString_withSimpleDateFormat() throws Exception {
    Field dateFormatsField = DefaultDateTypeAdapter.class.getDeclaredField("dateFormats");
    dateFormatsField.setAccessible(true);
    @SuppressWarnings("unchecked")
    List<DateFormat> dateFormats = (List<DateFormat>) dateFormatsField.get(adapter);
    dateFormats.clear();
    SimpleDateFormat sdf = new SimpleDateFormat("yyyy-MM-dd");
    dateFormats.add(sdf);

    String result = adapter.toString();

    assertEquals("DefaultDateTypeAdapter(yyyy-MM-dd)", result);
  }

  @Test
